#include <stdio.h>
#include <stdlib.h>

#define m 301000

int ns[m], es[m], c[m], b[m], t[m], P = 0;

void add(int *b, int k) {
    k = t[k];
    while (k) {
        int e = es[k];
        if (b[m - 1] > e) b[m - 1] = e;
        b[e]++;
        k = ns[k];
    }
}

int delete(int *b) {
    for (int i = b[m - 1]; i <= m; i++) {
        if (b[i]) {
            b[i]--;
            b[m - 1] = i;
            return i;
        }
    }
    return 0;
}

int calc(int k, int rank, int dn) {
    for (int i = 0; i < m; i++) b[i] = 0;
    b[m - 1] = m;
    int take = rank - dn;
    if (take < 0) take = 0;
    add(b, k);
    add(b, k - 1);
    int q = 0;
    for (int i = 1; i <= take; i++) q += delete(b);
    for (int i = 1; i < k; i++) add(b, i);
    for (int i = k + 1; i <= P; i++) add(b, i);
    for (int i = 1; i <= k - take; i++) q += delete(b);
    return q;
}

int main() {
    int n, k;
    scanf("%d %d", &n, &k);
    int rank = n - k + 1;

    if (rank == 0) {
        printf("0\n");
        return 0;
    }

    for (int i = 1; i <= n; i++) {
        int p, e;
        scanf("%d %d", &p, &e);
        if (p > P) P = p;
        c[p]++;
        es[i] = e;
        ns[i] = t[p];
        t[p] = i;
    }

    int dn = 0;
    for (int i = 1; i <= n; i++) {
        if (i > 1) dn += c[i - 2];
        if (c[i] + c[i - 1] + dn >= rank && rank <= i + dn) {
            int u = calc(i, rank, dn);
            if (i < n) {
                dn += c[i - 1];
                int v = calc(i + 1, rank, dn);
                if (u > v) u = v;
            }
            if (i < n - 1) {
                dn += c[i];
                int v = calc(i + 2, rank, dn);
                if (u > v) u = v;
            }
            printf("%d\n", u);
            return 0;
        }
    }

    printf("-1\n");
    return 0;
}
